import { defineStore } from 'pinia'
import axios from 'axios'
import { ElMessage } from 'element-plus'

export const useAgentStore = defineStore('agent', {
  state: () => ({
    agents: [],
    currentAgent: null,
    tasks: [],
    isLoading: false,
    error: null
  }),

  getters: {
    getAgents: (state) => state.agents,
    getCurrentAgent: (state) => state.currentAgent,
    getTasks: (state) => state.tasks,
    getIsLoading: (state) => state.isLoading,
    getError: (state) => state.error
  },

  actions: {
    // 获取智能体列表
    async fetchAgents() {
      this.isLoading = true
      this.error = null
      
      try {
        const response = await axios.get('/api/agents/')
        this.agents = response.data.results || response.data
      } catch (error) {
        this.error = '获取智能体列表失败'
        console.error(error)
      } finally {
        this.isLoading = false
      }
    },

    // 获取单个智能体详情
    async fetchAgent(id) {
      this.isLoading = true
      this.error = null
      
      try {
        const response = await axios.get(`/api/agents/${id}/`)
        this.currentAgent = response.data
      } catch (error) {
        this.error = '获取智能体详情失败'
        console.error(error)
      } finally {
        this.isLoading = false
      }
    },

    // 保存智能体
    async saveAgent(agentData) {
      this.isLoading = true
      this.error = null
      
      try {
        let response
        if (agentData.id) {
          // 更新现有智能体
          response = await axios.put(`/api/agents/${agentData.id}/`, agentData)
          ElMessage.success('智能体已成功更新')
        } else {
          // 创建新智能体
          response = await axios.post('/api/agents/', agentData)
          ElMessage.success('智能体已成功创建')
        }
        
        this.currentAgent = response.data
        return response.data
      } catch (error) {
        this.error = '保存智能体失败'
        ElMessage.error(this.error)
        console.error(error)
        throw error
      } finally {
        this.isLoading = false
      }
    },

    // 删除智能体
    async deleteAgent(id) {
      this.isLoading = true
      this.error = null
      
      try {
        await axios.delete(`/api/agents/${id}/`)
        // 从列表中移除
        this.agents = this.agents.filter(agent => agent.id !== id)
        ElMessage.success('智能体已成功删除')
        return true
      } catch (error) {
        this.error = '删除智能体失败'
        ElMessage.error(this.error)
        console.error(error)
        throw error
      } finally {
        this.isLoading = false
      }
    },

    // 获取智能体关联的任务
    async fetchAgentTasks(id) {
      this.isLoading = true
      this.error = null
      
      try {
        const response = await axios.get(`/api/agents/${id}/tasks/`)
        this.tasks = response.data.results || response.data
      } catch (error) {
        this.error = '获取智能体任务失败'
        console.error(error)
      } finally {
        this.isLoading = false
      }
    },

    // 发送聊天消息
    async sendChatMessage(agentId, message, systemPrompt) {
      this.isLoading = true
      this.error = null
      
      try {
        const response = await axios.post(`/api/agents/${agentId}/chat/`, {
          message,
          system_prompt: systemPrompt
        })
        return response.data
      } catch (error) {
        this.error = '发送消息失败'
        console.error(error)
        throw error
      } finally {
        this.isLoading = false
      }
    },

    // 创建A2A任务
    async createA2ATask(agentId, taskData) {
      this.isLoading = true
      this.error = null
      
      try {
        const response = await axios.post(`/api/agents/${agentId}/tasks/`, taskData)
        // 将新任务添加到任务列表
        if (this.tasks.length > 0) {
          this.tasks.unshift(response.data)
        }
        return response.data
      } catch (error) {
        this.error = '创建A2A任务失败'
        console.error(error)
        throw error
      } finally {
        this.isLoading = false
      }
    },

    // 获取任务详情
    async fetchTaskDetail(agentId, taskId) {
      this.isLoading = true
      this.error = null
      
      try {
        const response = await axios.get(`/api/agents/${agentId}/tasks/${taskId}/`)
        return response.data
      } catch (error) {
        this.error = '获取任务详情失败'
        console.error(error)
        throw error
      } finally {
        this.isLoading = false
      }
    },

    // 清空状态
    clearState() {
      this.agents = []
      this.currentAgent = null
      this.tasks = []
      this.error = null
    }
  }
}) 